import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
 * Sends a jukebox request:
 * - urlOrId: YouTube URL or 11-char ID
 * - expedite: true = move to front of queue
 */
export class JukeboxRequestComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(urlOrId: string, expedite: boolean = false) {
        const safeUrl = String(urlOrId || '').trim();
        const fast = Boolean(expedite);

        this._data = [safeUrl, fast];

        console.log('[📤] JukeboxRequestComposer packet sent:', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
